	public static bool TryGet(string language, string key, out string value)
	{
		if (Values.TryGetValue(language, out IReadOnlyDictionary<string, string> value2) && value2.TryGetValue(key, out var value3))
		{
			value = value3;
			return true;
		}
		if (StatusValues.TryGetValue(language, out value2) && value2.TryGetValue(key, out value3))
		{
			value = value3;
			return true;
		}
		value = key;
		return false;
	}

	private static IReadOnlyDictionary<string, string> D(params (string Key, string Value)[] entries)
	{
		Dictionary<string, string> dictionary = new Dictionary<string, string>(StringComparer.Ordinal);
		for (int i = 0; i < entries.Length; i++)
		{
			(string Key, string Value) tuple = entries[i];
			string item = tuple.Key;
			string item2 = tuple.Value;
			dictionary[item] = item2;
		}
		return dictionary;
	}
